              >
                {/* Initiative Circle */}
                <div className={`
                  w-14 h-14 rounded-full flex items-center justify-center text-2xl font-bold shrink-0
                  ${isActive ? 'bg-amber-500 text-stone-950' : 'bg-stone-800 text-stone-400'}
