  maxHp?: number;
  tempHp?: number;
  individualMaxHp?: number; // For shared health pools to track count
  ac: number;
  conditions: Condition[];
  type: 'player' | 'creature' | 'dmpc';
  level?: number; // For players/dmpcs
  cr?: number; // For creatures
