import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { AddParticipantForm } from './components/AddParticipantForm';
import { InitiativeList } from './components/InitiativeList';
import { CombatControls } from './components/CombatControls';
import { SaveLoadControls } from './components/SaveLoadControls';
import { StatblockModal } from './components/StatblockModal';
import { DescriptionViewerModal } from './components/DescriptionViewerModal';
import { RerollInitiativeModal } from './components/RerollInitiativeModal';
import { AddCreaturesModal } from './components/AddCreaturesModal';
import { LootModal } from './components/LootModal';
import { EncounterDifficulty } from './components/EncounterDifficulty';
import { TieBreakerModal } from './components/TieBreakerModal';
import { CombatLog } from './components/CombatLog';
import type { Participant, Condition, LogEntry } from './types';
import { D20Icon } from './components/icons';

interface SavedState {
  participants: Participant[];
  currentIndex: number;
  round: number;
  combatLog: LogEntry[];
}

const SYNC_CHANNEL = 'dnd_combat_sync';

const getRandomColor = () => {
    const colors = [
      'border-red-500 bg-red-900/20',
      'border-orange-500 bg-orange-900/20',
      'border-amber-500 bg-amber-900/20',
      'border-yellow-500 bg-yellow-900/20',
      'border-lime-500 bg-lime-900/20',
      'border-green-500 bg-green-900/20',
      'border-emerald-500 bg-emerald-900/20',
      'border-teal-500 bg-teal-900/20',
      'border-cyan-500 bg-cyan-900/20',
      'border-sky-500 bg-sky-900/20',
      'border-blue-500 bg-blue-900/20',
      'border-indigo-500 bg-indigo-900/20',
      'border-violet-500 bg-violet-900/20',
      'border-purple-500 bg-purple-900/20',
      'border-fuchsia-500 bg-fuchsia-900/20',
      'border-pink-500 bg-pink-900/20',
      'border-rose-500 bg-rose-900/20',
    ];
    return colors[Math.floor(Math.random() * colors.length)];
  };

/** 
 * Player View Component
 * A simplified, read-only view of the initiative for the players.
 */
const PlayerView: React.FC<{
  participants: Participant[];
  currentIndex: number;
  round: number;
}> = ({ participants, currentIndex, round }) => {
  const sorted = useMemo(() => {
    return [...participants].sort((a, b) => {
      if (b.initiative !== a.initiative) return b.initiative - a.initiative;
      const dexA = a.dexterityModifier ?? -Infinity;
      const dexB = b.dexterityModifier ?? -Infinity;
      if (dexB !== dexA) return dexB - dexA;
      return a.name.localeCompare(b.name);
    });
  }, [participants]);

  const getVitality = (p: Participant) => {
    if (typeof p.hp !== 'number' || typeof p.maxHp !== 'number' || p.maxHp <= 0) {
      return { label: 'Unknown', color: 'text-stone-500' };
    }

    if (p.hp === 0) {
        if (p.isInstantDead || (p.deathSavesFailure && p.deathSavesFailure >= 3)) {
            return { label: 'Deceased', color: 'text-red-700' };
        }
        if (p.type === 'player' || p.type === 'dmpc') {
            const s = p.deathSavesSuccess || 0;
            const f = p.deathSavesFailure || 0;
            return { label: `Dying (${s}S, ${f}F)`, color: 'text-red-500' };
        }
        return { label: 'Crippled', color: 'text-red-500' };
    }

    const percent = (p.hp / p.maxHp) * 100;
    if (percent > 75) return { label: 'Unscathed', color: 'text-emerald-400' };
    if (percent > 50) return { label: 'Bruised', color: 'text-lime-400' };
    if (percent > 25) return { label: 'Wounded', color: 'text-orange-400' };
    return { label: 'Crippled', color: 'text-red-500' };
  };

  return (
    <div className="min-h-screen bg-stone-950 p-6 md:p-12">
      <div className="max-w-5xl mx-auto">
        <header className="flex flex-col items-center mb-12 border-b border-stone-800 pb-8">
          <h1 className="text-4xl font-medieval text-amber-500 flex items-center gap-4 mb-2">
            <D20Icon className="w-8 h-8" />
            Initiative Order
            <D20Icon className="w-8 h-8" />
          </h1>
          {round > 0 ? (
            <div className="text-stone-400 text-xl font-medieval uppercase tracking-widest">
              Round <span className="text-white text-3xl font-bold">{round}</span>
            </div>
          ) : (
            <div className="text-stone-500 text-lg italic">Waiting for combat to begin...</div>
          )}
        </header>

        {/* Column Headers */}
        <div className="hidden md:grid grid-cols-12 gap-6 px-6 mb-4 text-xs font-bold uppercase tracking-widest text-stone-500">
          <div className="col-span-1 text-center">Init</div>
          <div className="col-span-8">Combatant</div>
          <div className="col-span-3 text-right pr-4">Vitality</div>
        </div>

        <ul className="space-y-4">
          {sorted.map((p, idx) => {
            const isActive = idx === currentIndex;
            const isDefeated = p.hp === 0;
            const vitality = getVitality(p);

            return (
              <li 
                key={p.id} 
                className={`
                  relative grid grid-cols-12 items-center gap-4 sm:gap-6 p-4 sm:p-6 rounded-xl border-2 transition-all duration-500
                  ${isActive 
                    ? 'bg-amber-900/20 border-amber-500/50 shadow-[0_0_20px_rgba(245,158,11,0.2)] scale-105 z-10' 
                    : 'bg-stone-900/40 border-stone-800 scale-100 opacity-90'}
                  ${isDefeated ? 'opacity-40 grayscale blur-[0.5px]' : ''}
                `}
              >
                {/* Initiative Column */}
                <div className="col-span-2 md:col-span-1 flex items-center justify-center">
                  <div className={`
                    w-10 h-10 sm:w-14 sm:h-14 rounded-full flex items-center justify-center text-xl sm:text-2xl font-bold shrink-0
                    ${isActive ? 'bg-amber-500 text-stone-950' : 'bg-stone-800 text-stone-400'}
                  `}>
                    {p.initiative}
                  </div>
                </div>

                {/* Info Column */}
                <div className="col-span-7 md:col-span-8 flex flex-col gap-1 overflow-hidden">
                  <div className="flex items-center gap-2 sm:gap-3 flex-wrap">
                    <span role="img" aria-label={p.type} className="text-xl sm:text-2xl">
                        {p.type === 'player' ? '🧑' : p.type === 'dmpc' ? '🎭' : '🐲'}
                    </span>
                    <span className={`text-xl sm:text-2xl font-medieval truncate ${isActive ? 'text-white' : 'text-stone-300'}`}>
                      {p.name}
                    </span>
                    {isActive && (
                      <span className="bg-amber-500 text-stone-950 text-[10px] font-bold px-2 py-0.5 rounded uppercase tracking-tighter animate-pulse">
                        Turn
                      </span>
                    )}
                  </div>

                  {/* Conditions */}
                  <div className="flex flex-wrap gap-1">
                    {p.conditions.map(c => (
                      <span key={c.id} className="bg-violet-900/60 text-violet-200 border border-violet-700/50 px-2 py-0.5 rounded-full text-[10px] sm:text-xs font-bold uppercase tracking-wider">
                        {c.name} {c.duration !== Infinity && `(${c.duration})`}
                      </span>
                    ))}
                  </div>
                </div>

                {/* Vitality Column */}
                <div className="col-span-3 text-right pr-2">
                   <div className={`text-sm sm:text-lg font-bold uppercase tracking-wide ${vitality.color}`}>
                     {vitality.label}
                   </div>
                   {isActive && (
                      <div className="text-amber-500 animate-[bounce_1s_infinite_horizontal] mt-2 hidden md:block">
                        <svg className="w-6 h-6 ml-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                        </svg>
                      </div>
                   )}
                </div>
              </li>
            );
          })}
        </ul>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [participants, setParticipants] = useState<Participant[]>([]);
  const [currentIndex, setCurrentIndex] = useState<number>(-1);
  const [round, setRound] = useState<number>(0);
  const [combatLog, setCombatLog] = useState<LogEntry[]>([]);
  const [detailsToShow, setDetailsToShow] = useState<{ url?: string; description?: string; title: string } | null>(null);
  const [loadedStateForReroll, setLoadedStateForReroll] = useState<SavedState | null>(null);
  const [creaturesToAdd, setCreaturesToAdd] = useState<Participant[] | null>(null);
  const [participantToFind, setParticipantToFind] = useState<string | null>(null);
  const [lootingParticipant, setLootingParticipant] = useState<Participant | null>(null);
  const [ties, setTies] = useState<Participant[][] | null>(null);

  // Sync state across windows - switched to Hash for Safari compatibility with Blob URLs
  const [isPlayerView, setIsPlayerView] = useState(() => window.location.hash === '#player');
  const channel = useMemo(() => new BroadcastChannel(SYNC_CHANNEL), []);

  useEffect(() => {
    const handleHashChange = () => setIsPlayerView(window.location.hash === '#player');
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  // Effect for Broadcasting (DM only)
  useEffect(() => {
    if (!isPlayerView) {
      channel.postMessage({
        type: 'SYNC',
        participants,
        currentIndex,
        round
      });
      // Also save to localStorage for window refreshes/initial loads
      localStorage.setItem('combat_state_sync', JSON.stringify({ participants, currentIndex, round }));
    }
  }, [participants, currentIndex, round, isPlayerView, channel]);

  // Effect for Listening (Player View only)
  useEffect(() => {
    if (isPlayerView) {
      // Load initial state
      const initial = localStorage.getItem('combat_state_sync');
      if (initial) {
        try {
          const data = JSON.parse(initial);
          setParticipants(data.participants);
          setCurrentIndex(data.currentIndex);
          setRound(data.round);
        } catch (e) { console.error("Sync error", e); }
      }

      const handleMessage = (event: MessageEvent) => {
        if (event.data.type === 'SYNC') {
          setParticipants(event.data.participants);
          setCurrentIndex(event.data.currentIndex);
          setRound(event.data.round);
        }
      };
      channel.addEventListener('message', handleMessage);
      return () => channel.removeEventListener('message', handleMessage);
    }
  }, [isPlayerView, channel]);

  const sortedParticipants = useMemo(() => {
    return [...participants].sort((a, b) => {
      if (b.initiative !== a.initiative) {
        return b.initiative - a.initiative;
      }
      const dexA = a.dexterityModifier ?? -Infinity;
      const dexB = b.dexterityModifier ?? -Infinity;
      if (dexB !== dexA) {
        return dexB - dexA;
      }
      return a.name.localeCompare(b.name); // Fallback to name sort
    });
  }, [participants]);

  const addLogEntry = useCallback((message: string, type: LogEntry['type'], actorNameOverride?: string) => {
    const actor = sortedParticipants[currentIndex];
    const newEntry: LogEntry = {
        id: `${Date.now()}-${Math.random()}`,
        round: round > 0 ? round : 0,
        actorName: actorNameOverride || actor?.name || 'System',
        message,
        type,
    };
    setCombatLog(prev => [...prev, newEntry]);
  }, [currentIndex, round, sortedParticipants]);

  // Effect to reset legendary actions at the start of a participant's turn
  useEffect(() => {
    if (currentIndex > -1 && sortedParticipants.length > 0) {
      const currentParticipant = sortedParticipants[currentIndex];
      if (
        currentParticipant &&
        typeof currentParticipant.legendaryActions === 'number' &&
        currentParticipant.legendaryActionsUsed !== 0
      ) {
        // It's this participant's turn, reset their actions
        setParticipants(prev =>
          prev.map(p =>
            p.id === currentParticipant.id ? { ...p, legendaryActionsUsed: 0 } : p
          )
        );
      }
    }
  }, [currentIndex, sortedParticipants]);

  // Effect to correctly set the current index after adding new creatures to an ongoing combat
  useEffect(() => {
    if (participantToFind && sortedParticipants.length > 0) {
        const newIndex = sortedParticipants.findIndex(p => p.id === participantToFind);
        if (newIndex > -1) {
            setCurrentIndex(newIndex);
        }
        setParticipantToFind(null); // Reset after use
    }
  }, [sortedParticipants, participantToFind]);

  const findTies = useCallback((participantsList: Participant[]): Participant[][] => {
    const initiatives = new Map<number, Participant[]>();
    participantsList.forEach(p => {
        if (!initiatives.has(p.initiative)) {
            initiatives.set(p.initiative, []);
        }
        initiatives.get(p.initiative)!.push(p);
    });

    const tiesFound: Participant[][] = [];
    initiatives.forEach(group => {
        if (group.length > 1) {
            const needsResolution = group.some(p => typeof p.dexterityModifier !== 'number');
            if (needsResolution) {
                tiesFound.push(group);
            }
        }
    });
    return tiesFound;
  }, []);

  const handleAddParticipant = (participantOrList: Omit<Participant, 'id'> | Omit<Participant, 'id'>[]) => {
    const inputList = Array.isArray(participantOrList) ? participantOrList : [participantOrList];

    const newItems = inputList.map((p, i) => ({
        ...p,
        id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}-${i}`,
        deathSavesSuccess: 0,
        deathSavesFailure: 0,
    }));

    const newParticipants = [...participants, ...newItems];

    if (currentIndex > -1) { // If combat is active, check for ties immediately
      const tiesToResolve = findTies(newParticipants);
      if (tiesToResolve.length > 0) {
        setParticipants(newParticipants); // Add participant to state first
        setTies(tiesToResolve); // Then open modal
        return;
      }
    }
    setParticipants(newParticipants);
  };

  const handleRemoveParticipant = (id: string) => {
    const participantToRemove = participants.find(p => p.id === id);
    if (participantToRemove) {
      addLogEntry(`${participantToRemove.name} was removed from combat.`, 'info');
    }

    if (lootingParticipant?.id === id) {
      setLootingParticipant(null);
    }

    const removedIndex = sortedParticipants.findIndex(p => p.id === id);
    const newParticipants = participants.filter(p => p.id !== id);
    setParticipants(newParticipants);

    if (newParticipants.length === 0) {
      setCurrentIndex(-1);
      setRound(0);
      return;
    }

    if (currentIndex > -1) {
      if (removedIndex < currentIndex) {
        setCurrentIndex(prev => prev - 1);
      } else if (removedIndex === currentIndex) {
         if (currentIndex >= newParticipants.length) {
            setCurrentIndex(0);
            setRound(prev => prev + 1);
         }
      }
    }
  };

  const handleUpdateParticipant = useCallback((id: string, updates: Partial<Participant>) => {
    const participant = participants.find(p => p.id === id);
    if (!participant) return;

    let finalUpdates = { ...updates };

    // Log HP changes
    if (updates.hp !== undefined && typeof participant.hp === 'number') {
        const oldHp = participant.hp;
        const newHp = Math.max(0, updates.hp);
        if (newHp < oldHp) {
            addLogEntry(`${participant.name} takes ${oldHp - newHp} damage.`, 'damage');
        } else if (newHp > oldHp) {
            addLogEntry(`${participant.name} heals for ${newHp - oldHp} hit points.`, 'healing');

            // Healing resets death saves for players/DMPCs
            if (oldHp === 0 && (participant.type === 'player' || participant.type === 'dmpc')) {
                finalUpdates.deathSavesSuccess = 0;
                finalUpdates.deathSavesFailure = 0;
                finalUpdates.isInstantDead = false;
            }
        }

        // Instant Death check
        if (updates.isInstantDead) {
            addLogEntry(`${participant.name} died instantly from massive damage!`, 'death');
        } else if (newHp <= 0 && oldHp > 0) {
            addLogEntry(`${participant.name} has been defeated!`, 'death');
        }
    }

    // Log Temp HP changes
    if (updates.tempHp !== undefined) {
         const oldTempHp = participant.tempHp || 0;
         const newTempHp = Math.max(0, updates.tempHp);
         if (newTempHp > oldTempHp) {
             addLogEntry(`${participant.name} gains ${newTempHp - oldTempHp} temporary hit points.`, 'info');
         }
    }

    if (currentIndex > -1 && updates.initiative !== undefined && sortedParticipants[currentIndex]) {
        setParticipantToFind(sortedParticipants[currentIndex].id);
    }

    // Logic for Mob Count Update (Shared Health)
    if (updates.hp !== undefined && participant.individualMaxHp && participant.individualMaxHp > 0) {
        const newHp = Math.max(0, updates.hp);
        const count = Math.ceil(newHp / participant.individualMaxHp);
        // Look for (xN) pattern to replace
        if (/\(x\d+\)/.test(participant.name)) {
             finalUpdates.name = participant.name.replace(/\(x\d+\)/, `(x${count})`);
        }
    }

    setParticipants(prev => {
        // Check if we are updating initiative for a grouped participant
        if (finalUpdates.initiative !== undefined && participant.group) {
            // Update all participants in the same group
            return prev.map(p => {
                if (p.group && p.group.id === participant.group!.id) {
                    return { ...p, ...finalUpdates };
                }
                return p;
            });
        }

        // Otherwise just update the single participant
        return prev.map(p => (p.id === id ? { ...p, ...finalUpdates } : p));
    });
  }, [participants, currentIndex, sortedParticipants, addLogEntry]);

  const handleStart = () => {
    if (participants.length > 0) {
      const tiesToResolve = findTies(participants);
      if (tiesToResolve.length > 0) {
        setTies(tiesToResolve);
        return;
      }
      setCombatLog([]); // Clear log for new combat
      const firstParticipant = sortedParticipants[0];
      setRound(1);
      setCurrentIndex(0);

      const newLog: LogEntry[] = [
        { id: `${Date.now()}-start`, round: 1, actorName: 'System', message: 'Combat has started! Round 1 begins.', type: 'info' },
        { id: `${Date.now()}-turn`, round: 1, actorName: firstParticipant.name, message: `It is now ${firstParticipant.name}'s turn.`, type: 'turn_start' }
      ];
      setCombatLog(newLog);
    }
  };

  const handleNext = () => {
    if (sortedParticipants.length > 0) {
      let currentRound = round;
      const nextIndex = (currentIndex + 1) % sortedParticipants.length;

      if (nextIndex === 0) {
        currentRound = round + 1;
        setRound(currentRound);
        addLogEntry(`Round ${currentRound} begins.`, 'info');
        // New round begins, update condition durations
        setParticipants(prev => prev.map(p => ({
            ...p,
            conditions: p.conditions
                .map(c => ({ ...c, duration: c.duration !== Infinity ? c.duration - 1 : Infinity }))
                .filter(c => c.duration > 0 || c.duration === Infinity)
        })));
      }

      const nextParticipant = sortedParticipants[nextIndex];
      addLogEntry(`It is now ${nextParticipant.name}'s turn.`, 'turn_start', nextParticipant.name);
      setCurrentIndex(nextIndex);
    }
  };

  const handlePrev = () => {
     if (sortedParticipants.length > 0) {
      const prevIndex = (currentIndex - 1 + sortedParticipants.length) % sortedParticipants.length;
       if (currentIndex === 0) {
         setRound(prev => Math.max(1, prev - 1));
       }
      setCurrentIndex(prevIndex);
    }
  };

  const handleEndCombat = () => {
    addLogEntry('Combat has ended.', 'info');
    setCurrentIndex(-1);
    setRound(0);
    setParticipants(prev =>
      prev.filter(p => {
        if (p.type === 'player') return true; // Always keep players

        const isDefeated = typeof p.hp === 'number' && p.hp <= 0;
        if (!isDefeated) return true; // Keep anyone not defeated

        // At this point, it's a defeated non-player. Keep only if they have loot.
        const hasLoot = p.inventory && p.inventory.length > 0;
        return hasLoot;
      })
    );
  };

  const handleResetCombat = () => {
    if (confirm("Are you sure you want to simulate a long rest? This will reset all combatants to full health, remove all conditions, and reset resources. This cannot be undone.")) {
        setParticipants(prev => prev.map(p => ({
            ...p,
            hp: p.maxHp,
            tempHp: 0,
            conditions: [],
            legendaryResistancesUsed: 0,
            legendaryActionsUsed: 0,
            deathSavesSuccess: 0,
            deathSavesFailure: 0,
            isInstantDead: false,
        })));
        setCurrentIndex(-1);
        setRound(0);
        setCombatLog([]);
        addLogEntry('Combat has been reset.', 'info');
    }
  };

  const handleClearInitiative = () => {
    setParticipants([]);
    setCurrentIndex(-1);
    setRound(0);
    setCombatLog([]);
    addLogEntry('Battlefield has been cleared.', 'info', 'System');
  };

  const handleAddCondition = (participantId: string, condition: Omit<Condition, 'id'>) => {
    const participant = participants.find(p => p.id === participantId);
    if (participant) {
        addLogEntry(`${participant.name} is now ${condition.name}.`, 'condition_add');
    }
    setParticipants(prev => prev.map(p => {
        if (p.id === participantId) {
            return {
                ...p,
                conditions: [...p.conditions, { ...condition, id: Date.now().toString() }]
            };
        }
        return p;
    }));
  };

  const handleRemoveCondition = (participantId: string, conditionId: string) => {
      const participant = participants.find(p => p.id === participantId);
      if (participant) {
        const condition = participant.conditions.find(c => c.id === conditionId);
        if (condition) {
            addLogEntry(`${participant.name} is no longer ${condition.name}.`, 'condition_remove');
        }
      }
      setParticipants(prev => prev.map(p => {
          if (p.id === participantId) {
              return {
                  ...p,
                  conditions: p.conditions.filter(c => c.id !== conditionId)
              };
          }
          return p;
      }));
  };

  const handleSaveState = () => {
    try {
      const stateToSave: SavedState = {
        participants,
        currentIndex,
        round,
        combatLog,
      };
      const dataStr = JSON.stringify(stateToSave, null, 2);
      const dataBlob = new Blob([dataStr], { type: 'application/json' });
      const url = URL.createObjectURL(dataBlob);
      const link = document.createElement('a');
      link.href = url;
      const timestamp = new Date().toISOString().split('T')[0];
      link.download = `dnd-initiative-save-${timestamp}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error("Failed to save state:", error);
      alert("An error occurred while trying to save the session.");
    }
  };

  const handleLoadState = (file: File) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const result = event.target?.result;
        if (typeof result !== 'string') {
          throw new Error("Failed to read file content.");
        }
        const loadedState = JSON.parse(result);

        if (
          Array.isArray(loadedState.participants) &&
          typeof loadedState.currentIndex === 'number' &&
          typeof loadedState.round === 'number'
        ) {
          const stateWithLog: SavedState = {
            ...loadedState,
            combatLog: loadedState.combatLog || []
          };
          setLoadedStateForReroll(stateWithLog);
        } else {
          throw new Error("Invalid save file format.");
        }
      } catch (error) {
        console.error("Failed to load state:", error);
        alert("Error: Could not load the save file. It may be corrupted or in an incorrect format.");
      }
    };
    reader.onerror = () => {
      alert("Error: Failed to read the selected file.");
    };
    reader.readAsText(file);
  };

  const handleAddCreaturesFromFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const result = event.target?.result;
        if (typeof result !== 'string') throw new Error("Failed to read file content.");
        const loadedState: SavedState = JSON.parse(result);

        if (!Array.isArray(loadedState.participants)) throw new Error("Invalid save file format.");

        const creaturesOnly = loadedState.participants.filter(p => p.type === 'creature');
        if (creaturesOnly.length > 0) {
            setCreaturesToAdd(creaturesOnly);
        } else {
            alert("The selected file contains no creatures to add.");
        }
      } catch (error) {
        console.error("Failed to load creatures from file:", error);
        alert("Error: Could not load creatures from the file. It may be corrupted or in an incorrect format.");
      }
    };
    reader.onerror = () => {
      alert("Error: Failed to read the selected file.");
    };
    reader.readAsText(file);
  };

  const handleConfirmAddCreatures = (creaturesWithNewInitiative: Participant[]) => {
    if (currentIndex > -1 && sortedParticipants[currentIndex]) {
        setParticipantToFind(sortedParticipants[currentIndex].id);
    }

    const newCreaturesWithIds = creaturesWithNewInitiative.map((c, index) => ({
        ...c,
        id: `${Date.now()}-${c.name}-${index}`, // More robust ID
        deathSavesSuccess: 0,
        deathSavesFailure: 0,
    }));

    const newTotalParticipants = [...participants, ...newCreaturesWithIds];

    if (currentIndex > -1) { // Only check for ties if combat is already running
        const tiesToResolve = findTies(newTotalParticipants);
        if (tiesToResolve.length > 0) {
            setParticipants(newTotalParticipants);
            setTies(tiesToResolve);
            setCreaturesToAdd(null);
            return;
        }
    }

    setParticipants(newTotalParticipants);
    setCreaturesToAdd(null);
  };

  const handleConfirmLoadAsIs = (stateToLoad: SavedState) => {
    setParticipants(stateToLoad.participants);
    setCurrentIndex(stateToLoad.currentIndex);
    setRound(stateToLoad.round);
    setCombatLog(stateToLoad.combatLog || []);
    setLoadedStateForReroll(null);
  };

  const handleConfirmUpdateInitiative = (updatedParticipants: Participant[]) => {
      setParticipants(updatedParticipants);
      setCurrentIndex(-1);
      setRound(0);
      setCombatLog([]);
      setLoadedStateForReroll(null);
  };

  const handleCancelLoad = () => {
      setLoadedStateForReroll(null);
  };

  const handleResolveTies = (updatedParticipantsFromModal: Participant[]) => {
    const updatedMap = new Map(updatedParticipantsFromModal.map(p => [p.id, p]));
    setParticipants(prev => prev.map(p => updatedMap.get(p.id) || p));
    setTies(null);

    // If combat wasn't started, start it now.
    if (currentIndex === -1 && round === 0) {
      handleStart();
    }
  };

  const handleOpenPlayerView = () => {
    const baseUrl = window.location.href.split('#')[0].split('?')[0];
    const playerUrl = `${baseUrl}#player`;
    window.open(playerUrl, '_blank');
  };

  // Grouping Logic
  const handleGroupParticipants = (ids: string[]) => {
      if (ids.length < 2) return;
      const groupId = `${Date.now()}-group`;
      const color = getRandomColor();

      // Determine Shared Initiative: Use the initiative of the first participant in the selected list (or sort them first)
      const firstP = participants.find(p => p.id === ids[0]);
      const sharedInitiative = firstP ? firstP.initiative : 0;
      const groupName = firstP ? `${firstP.name} Group` : 'Group';

      setParticipants(prev => prev.map(p => {
          if (ids.includes(p.id)) {
              return {
                  ...p,
                  initiative: sharedInitiative, // Sync initiative
                  group: { id: groupId, name: groupName, color }
              };
          }
          return p;
      }));
  };

  const handleUngroupParticipants = (ids: string[]) => {
       setParticipants(prev => prev.map(p => {
          if (ids.includes(p.id)) {
              // eslint-disable-next-line @typescript-eslint/no-unused-vars
              const { group, ...rest } = p;
              return rest;
          }
          return p;
      }));
  };

  if (isPlayerView) {
    return <PlayerView participants={participants} currentIndex={currentIndex} round={round} />;
  }

  return (
    <div className="min-h-screen p-4 sm:p-6 lg:p-8">
      <div className="max-w-7xl mx-auto">
        <header className="text-center mb-8">
          <h1 className="text-5xl md:text-6xl font-medieval text-amber-500 flex items-center justify-center gap-4">
            <D20Icon className="w-12 h-12" />
            Encounter Tracker
            <D20Icon className="w-12 h-12" />
          </h1>
          <p className="text-stone-400 mt-2">The battle awaits. May the dice be ever in your favor.</p>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-8">
            <InitiativeList
              participants={sortedParticipants}
              currentIndex={currentIndex}
              onRemove={handleRemoveParticipant}
              onUpdateParticipant={handleUpdateParticipant}
              onAddCondition={handleAddCondition}
              onRemoveCondition={handleRemoveCondition}
              onViewDetails={setDetailsToShow}
              onLoot={setLootingParticipant}
              onGroup={handleGroupParticipants}
              onUngroup={handleUngroupParticipants}
            />
            <CombatLog entries={combatLog} />
          </div>

          <div className="space-y-8">
            <CombatControls
              round={round}
              isCombatStarted={currentIndex > -1}
              onStart={handleStart}
              onNext={handleNext}
              onPrev={handlePrev}
              onEnd={handleEndCombat}
              onReset={handleResetCombat}
              onClear={handleClearInitiative}
              onOpenPlayerView={handleOpenPlayerView}
              hasParticipants={participants.length > 0}
            />
            <EncounterDifficulty participants={participants} />
            <AddParticipantForm onAdd={handleAddParticipant} />
            <SaveLoadControls 
              onSave={handleSaveState}
              onLoad={handleLoadState}
              onAddFromFile={handleAddCreaturesFromFile}
              hasParticipants={participants.length > 0}
            />
          </div>
        </div>
      </div>
       {detailsToShow?.url && (
        <StatblockModal 
          url={detailsToShow.url}
          title={detailsToShow.title}
          onClose={() => setDetailsToShow(null)}
        />
      )}
      {detailsToShow?.description && (
        <DescriptionViewerModal
          description={detailsToShow.description}
          title={detailsToShow.title}
          onClose={() => setDetailsToShow(null)}
        />
      )}
      {loadedStateForReroll && (
        <RerollInitiativeModal
          loadedState={loadedStateForReroll}
          onConfirmLoadAsIs={handleConfirmLoadAsIs}
          onConfirmUpdateInitiative={handleConfirmUpdateInitiative}
          onClose={handleCancelLoad}
        />
      )}
      {creaturesToAdd && (
        <AddCreaturesModal
            creatures={creaturesToAdd}
            onConfirm={handleConfirmAddCreatures}
            onClose={() => setCreaturesToAdd(null)}
        />
      )}
      {lootingParticipant && (
        <LootModal 
          participant={lootingParticipant}
          onClose={() => setLootingParticipant(null)}
        />
      )}
      {ties && (
        <TieBreakerModal
            ties={ties}
            onResolve={handleResolveTies}
            onClose={() => setTies(null)}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import type { Participant, Condition } from '../types';
import { ShieldIcon, HeartIcon, TrashIcon, EditIcon, CheckIcon, PlusIcon, BookOpenIcon, DiamondIcon, StarIcon, LootIcon } from './icons';
import { ConditionManager } from './ConditionManager';
import { HealthManagerModal } from './HealthManagerModal';

interface ParticipantItemProps {
  participant: Participant;
  isActive: boolean;
  isCombatActive: boolean;
  onRemove: (id: string) => void;
  onUpdateParticipant: (id: string, updates: Partial<Participant>) => void;
  onAddCondition: (participantId: string, condition: Omit<Condition, 'id'>) => void;
  onRemoveCondition: (participantId: string, conditionId: string) => void;
  onViewDetails: (details: { url?: string; description?: string; title: string }) => void;
  onLoot: (participant: Participant) => void;
  isSelectionMode?: boolean;
  isSelected?: boolean;
  onToggleSelection?: () => void;
  isInGroup?: boolean;
}

const TraitGrid: React.FC<{ participant: Participant }> = ({ participant }) => {
    const { damageVulnerabilities, damageResistances, damageImmunities, conditionImmunities } = participant;

    const hasTraits = [damageVulnerabilities, damageResistances, damageImmunities, conditionImmunities].some(arr => arr && arr.length > 0);
    if (!hasTraits) return null;

    const leftColHasItems = (damageVulnerabilities && damageVulnerabilities.length > 0) || (damageResistances && damageResistances.length > 0);
    const rightColHasItems = (damageImmunities && damageImmunities.length > 0) || (conditionImmunities && conditionImmunities.length > 0);

    return (
        <div className={`col-span-12 mt-3 pt-3 border-t border-stone-700/60 grid grid-cols-1 ${leftColHasItems && rightColHasItems ? 'md:grid-cols-2' : ''} gap-x-6 gap-y-4 text-xs`}>
            {/* Left Column: Vulnerabilities & Resistances */}
            {leftColHasItems && (
                <div>
                    {damageVulnerabilities && damageVulnerabilities.length > 0 && (
                        <div className="mb-3">
                            <h5 className="font-bold text-red-400 mb-1 uppercase tracking-wider">Vulnerable</h5>
                            <div className="flex flex-wrap gap-1.5">
                                {damageVulnerabilities.map(v => <span key={v} className="px-2 py-1 bg-red-900/50 text-red-300 rounded">{v}</span>)}
                            </div>
                        </div>
                    )}
                    {damageResistances && damageResistances.length > 0 && (
                        <div>
                            <h5 className="font-bold text-sky-400 mb-1 uppercase tracking-wider">Resistant</h5>
                            <div className="flex flex-wrap gap-1.5">
                                {damageResistances.map(r => <span key={r} className="px-2 py-1 bg-sky-900/50 text-sky-300 rounded">{r}</span>)}
                            </div>
                        </div>
                    )}
                </div>
            )}
            {/* Right Column: Immunities */}
            {rightColHasItems && (
                <div>
                    {damageImmunities && damageImmunities.length > 0 && (
                        <div className="mb-3">
                            <h5 className="font-bold text-violet-400 mb-1 uppercase tracking-wider">Damage Immune</h5>
                            <div className="flex flex-wrap gap-1.5">
                                {damageImmunities.map(i => <span key={i} className="px-2 py-1 bg-violet-900/50 text-violet-300 rounded">{i}</span>)}
                            </div>
                        </div>
                    )}
                    {conditionImmunities && conditionImmunities.length > 0 && (
                        <div>
                            <h5 className="font-bold text-stone-400 mb-1 uppercase tracking-wider">Condition Immune</h5>
                            <div className="flex flex-wrap gap-1.5">
                                {conditionImmunities.map(ci => <span key={ci} className="px-2 py-1 bg-stone-700/50 text-stone-300 rounded">{ci}</span>)}
                            </div>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

const LegendaryTracker: React.FC<{
    label: string;
    max: number;
    used: number;
    onUpdate: (newUsed: number) => void;
    Icon: React.FC<React.SVGProps<SVGSVGElement>>;
    colorClass: string;
    usedColorClass: string;
}> = ({ label, max, used, onUpdate, Icon, colorClass, usedColorClass }) => {

    const toggleUsage = (index: number) => {
        const newUsed = index + 1 === used ? index : index + 1;
        onUpdate(newUsed);
    };

    return (
        <div>
            <h5 className={`font-bold text-sm ${colorClass} uppercase tracking-wider`}>{label}</h5>
            <div className="flex flex-wrap gap-1.5 mt-1">
                {Array.from({ length: max }).map((_, i) => (
                    <button 
                        key={i} 
                        onClick={() => toggleUsage(i)}
                        className="focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-stone-800 focus:ring-white rounded-full transition-colors"
                        aria-label={`${label} ${i + 1} of ${max}. ${i < used ? 'Used' : 'Available'}.`}
                    >
                        <Icon className={`w-6 h-6 ${i < used ? usedColorClass : colorClass}`} />
                    </button>
                ))}
            </div>
        </div>
    );
};

const DeathSaveTracker: React.FC<{
    participant: Participant;
    onUpdate: (updates: Partial<Participant>) => void;
}> = ({ participant, onUpdate }) => {
    const s = participant.deathSavesSuccess || 0;
    const f = participant.deathSavesFailure || 0;

    const setSuccess = (val: number) => onUpdate({ deathSavesSuccess: val === s ? val - 1 : val });
    const setFailure = (val: number) => onUpdate({ deathSavesFailure: val === f ? val - 1 : val });

    return (
        <div className="flex flex-col gap-2 p-2 bg-stone-900/40 rounded border border-stone-700">
            <div className="flex items-center justify-between gap-4">
                 <div className="flex flex-col gap-1">
                    <span className="text-[10px] font-bold text-stone-500 uppercase tracking-tighter">Successes</span>
                    <div className="flex gap-1.5">
                        {[1, 2, 3].map(i => (
                            <button
                                key={i}
                                onClick={() => setSuccess(i)}
                                className={`w-5 h-5 rounded-full border transition-all ${i <= s ? 'bg-emerald-500 border-emerald-400 shadow-[0_0_8px_rgba(16,185,129,0.3)]' : 'border-stone-600 hover:border-emerald-500/50'}`}
                            />
                        ))}
                    </div>
                </div>
                <div className="flex flex-col gap-1 items-end">
                    <span className="text-[10px] font-bold text-stone-500 uppercase tracking-tighter">Failures</span>
                    <div className="flex gap-1.5">
                        {[1, 2, 3].map(i => (
                            <button
                                key={i}
                                onClick={() => setFailure(i)}
                                className={`w-5 h-5 rounded-full border transition-all flex items-center justify-center ${i <= f ? 'bg-red-600 border-red-500 shadow-[0_0_8px_rgba(220,38,38,0.3)]' : 'border-stone-600 hover:border-red-500/50'}`}
                            >
                                {i <= f && <span className="text-[8px] text-white">💀</span>}
                            </button>
                        ))}
                    </div>
                </div>
            </div>
            {f >= 3 && <p className="text-[10px] text-red-500 font-bold text-center uppercase tracking-widest animate-pulse">Deceased</p>}
            {s >= 3 && <p className="text-[10px] text-emerald-500 font-bold text-center uppercase tracking-widest">Stable</p>}
        </div>
    );
};


export const ParticipantItem: React.FC<ParticipantItemProps> = ({
  participant,
  isActive,
  isCombatActive,
  onRemove,
  onUpdateParticipant,
  onAddCondition,
  onRemoveCondition,
  onViewDetails,
  onLoot,
  isSelectionMode,
  isSelected,
  onToggleSelection,
  isInGroup
}) => {
  const [isManagingHealth, setIsManagingHealth] = useState(false);
  const [isManagingConditions, setIsManagingConditions] = useState(false);
  const [isEditingInitiative, setIsEditingInitiative] = useState(false);
  const [newInitiative, setNewInitiative] = useState(participant.initiative.toString());
  const [isConfirmingDelete, setIsConfirmingDelete] = useState(false);
  const confirmDeleteTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    if (!isEditingInitiative) {
        setNewInitiative(participant.initiative.toString());
    }
  }, [participant.initiative, isEditingInitiative]);

  // Cleanup timeout on component unmount
  useEffect(() => {
    return () => {
        if (confirmDeleteTimeoutRef.current) {
            clearTimeout(confirmDeleteTimeoutRef.current);
        }
    };
  }, []);

  const handleInitiativeUpdate = () => {
    const initiativeValue = parseInt(newInitiative, 10);
    if (!isNaN(initiativeValue) && initiativeValue !== participant.initiative) {
      onUpdateParticipant(participant.id, { initiative: initiativeValue });
    }
    setIsEditingInitiative(false);
  };

  const handleInitiativeKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleInitiativeUpdate();
    } else if (e.key === 'Escape') {
      setIsEditingInitiative(false);
      setNewInitiative(participant.initiative.toString());
    }
  };

  const handleDeleteClick = () => {
    if (isConfirmingDelete) {
        if (confirmDeleteTimeoutRef.current) {
            clearTimeout(confirmDeleteTimeoutRef.current);
        }
        onRemove(participant.id);
    } else {
        setIsConfirmingDelete(true);
        confirmDeleteTimeoutRef.current = window.setTimeout(() => {
            setIsConfirmingDelete(false);
        }, 3000); // 3 seconds to confirm
    }
  };


  const handleLootClick = () => {
    onLoot(participant);
  };

  const hasHp = typeof participant.hp === 'number' && typeof participant.maxHp === 'number' && participant.maxHp > 0;
  const currentHp = participant.hp ?? 0;
  const maxHp = participant.maxHp ?? 1;
  const tempHp = participant.tempHp ?? 0;

  // HP Bar calculations
  const hpPercentage = hasHp ? (currentHp / maxHp) * 100 : 0;
  const hpColorClass = hpPercentage > 50 ? 'bg-emerald-500' : hpPercentage > 25 ? 'bg-amber-500' : 'bg-red-600';

  const totalEffectiveHp = currentHp + tempHp;
  const totalBarFillPercentage = hasHp ? (Math.min(totalEffectiveHp, maxHp) / maxHp) * 100 : 0;

  const hpSegmentPercentage = totalEffectiveHp > 0 ? (currentHp / totalEffectiveHp) * 100 : 0;
  const tempHpSegmentPercentage = totalEffectiveHp > 0 ? (tempHp / totalEffectiveHp) * 100 : 0;

  const isDead = typeof participant.hp === 'number' && participant.hp <= 0;
  const isTrulyDead = isDead && (participant.isInstantDead || (participant.deathSavesFailure && participant.deathSavesFailure >= 3));

  const hasLegendaryResistances = participant.type !== 'player' && participant.legendaryResistances && participant.legendaryResistances > 0;
  const hasLegendaryActions = participant.type !== 'player' && participant.legendaryActions && participant.legendaryActions > 0;
  const showLootButton = !isCombatActive && isDead && (participant.type === 'creature' || participant.type === 'dmpc');

  const detailsUrl = participant.characterSheetUrl || participant.statblockUrl;
  const hasDetails = detailsUrl || participant.description;

  // Style calculations
  const baseClasses = `
    relative grid grid-cols-12 gap-x-4 gap-y-2 items-center p-3 transition-all duration-300
    ${isDead ? 'opacity-70' : ''}
    ${isTrulyDead ? 'opacity-50 grayscale' : ''}
  `;

  // Group vs Single Styles
  const containerClasses = isInGroup 
    ? `${baseClasses} border-b border-stone-700/50 last:border-0 ${isActive ? 'bg-amber-900/20' : ''}`
    : `${baseClasses} rounded-lg ${isActive ? 'bg-stone-700/80 ring-2 ring-amber-500' : 'bg-stone-800/50 hover:bg-stone-700/80'}`;

  const selectionCheckbox = isSelectionMode ? (
    <div className={`absolute ${isInGroup ? 'left-2' : '-left-3'} top-1/2 -translate-y-1/2 z-10`}>
        <input 
            type="checkbox" 
            checked={isSelected} 
            onChange={onToggleSelection}
            className="h-5 w-5 rounded-full border-stone-400 text-amber-600 focus:ring-amber-500 cursor-pointer"
        />
    </div>
  ) : null;

  return (
    <>
      <div className={containerClasses}>
        {selectionCheckbox}

        {/* Initiative Column (Hidden if in group) */}
        {!isInGroup ? (
            <div className="col-span-1 text-2xl font-bold text-center flex items-center justify-center">
                {isEditingInitiative ? (
                    <div className="flex items-center gap-1">
                        <input
                            type="number"
                            value={newInitiative}
                            onChange={(e) => setNewInitiative(e.target.value)}
                            onKeyDown={handleInitiativeKeyDown}
                            onBlur={handleInitiativeUpdate}
                            className="w-16 bg-stone-900 text-white text-center rounded-md p-1 border border-stone-600 text-xl"
                            autoFocus
                        />
                        <button onClick={handleInitiativeUpdate} className="p-1 text-emerald-400 hover:text-emerald-300 rounded-full">
                            <CheckIcon className="w-5 h-5"/>
                        </button>
                    </div>
                ) : (
                    <div 
                        className="flex items-center justify-center gap-2 group cursor-pointer p-1 rounded-md"
                        onClick={() => setIsEditingInitiative(true)}
                        title="Click to edit initiative"
                    >
                        <span>{participant.initiative}</span>
                        <div className="opacity-0 group-hover:opacity-100 transition-opacity text-stone-400">
                            <EditIcon className="w-4 h-4" />
                        </div>
                    </div>
                )}
            </div>
        ) : (
             <div className="hidden"></div>
        )}

        {/* Main Content: Name & Status */}
        <div className={`${isInGroup ? 'col-span-5' : 'col-span-4'} flex flex-col`}>
          <div className="flex items-center gap-2">
             <span role="img" aria-label={participant.type} className="text-xl">
                {participant.type === 'player' ? '🧑' : participant.type === 'dmpc' ? '🎭' : '🐲'}
             </span>
            <span className={`font-bold text-lg ${isTrulyDead ? 'line-through text-stone-400' : isDead ? 'text-red-300' : 'text-white'}`}>
                {participant.name}
            </span>
             {hasDetails ? (
                <button 
                    onClick={() => {
                      if (participant.description) {
                        onViewDetails({ description: participant.description, title: `${participant.name}'s Description` });
                      } else if (detailsUrl) {
                        onViewDetails({ url: detailsUrl, title: `${participant.name}'s Sheet` });
                      }
                    }}
                    title={participant.description ? 'View Description' : (participant.characterSheetUrl ? 'View Character Sheet' : 'View Statblock')}
                >
                    <BookOpenIcon className="w-5 h-5 text-stone-400 hover:text-amber-400 transition" />
                </button>
            ) : null}
          </div>
          {isTrulyDead && <span className="text-[10px] text-red-500 font-bold ml-7 uppercase tracking-widest">Deceased</span>}
          {isDead && !isTrulyDead && <span className="text-[10px] text-red-400 font-bold ml-7 uppercase tracking-widest animate-pulse">Unconscious</span>}
          <div className="flex flex-wrap gap-1 mt-1 ml-7">
              {participant.conditions.map(condition => (
                  <span key={condition.id} className="px-2 py-0.5 text-xs bg-violet-800 text-violet-100 rounded-full">
                      {condition.name} {condition.duration !== Infinity && `(${condition.duration})`}
                  </span>
              ))}
          </div>
        </div>

        {/* HP Bar or Death Saves */}
        <div className="col-span-3 flex flex-col justify-center">
            {isDead && (participant.type === 'player' || participant.type === 'dmpc') ? (
                <DeathSaveTracker 
                    participant={participant} 
                    onUpdate={(u) => onUpdateParticipant(participant.id, u)} 
                />
            ) : hasHp ? (
                <>
                    <div className="flex items-center gap-2 text-sm">
                        <span>
                            {currentHp}
                            {tempHp > 0 && <span className="text-sky-400 font-bold"> +{tempHp}</span>}
                            &nbsp;/ {maxHp}
                        </span>
                    </div>
                    <div className="w-full bg-stone-900 rounded-full h-2.5 mt-1">
                        <div
                            className="h-2.5 flex"
                            style={{ width: `${totalBarFillPercentage}%` }}
                            title={`HP: ${currentHp}, Temp HP: ${tempHp}`}
                        >
                            {currentHp > 0 && (
                                <div
                                    className={`${hpColorClass} h-full ${tempHp <= 0 ? 'rounded-full' : 'rounded-l-full'}`}
                                    style={{ width: `${hpSegmentPercentage}%` }}
                                ></div>
                            )}
                            {tempHp > 0 && (
                                <div
                                    className={`bg-sky-400 h-full ${currentHp <= 0 ? 'rounded-full' : 'rounded-r-full'}`}
                                    style={{ width: `${tempHpSegmentPercentage}%` }}
                                ></div>
                            )}
                        </div>
                    </div>
                </>
            ) : (
                <div className="text-stone-500 text-sm">HP not tracked</div>
            )}
        </div>

        {/* AC */}
        <div className="col-span-1 flex items-center justify-center gap-1">
          <ShieldIcon className="w-5 h-5 text-sky-400" />
          <span className="font-bold text-lg">{participant.ac}</span>
        </div>

        {/* Actions */}
        <div className="col-span-3 flex items-center justify-end gap-1">
          {showLootButton ? (
             <button 
                onClick={handleLootClick}
                className="p-2 bg-amber-700/80 hover:bg-amber-600 text-white font-bold text-sm rounded-md transition flex items-center gap-1"
                aria-label={`Loot ${participant.name}`}
            >
                <LootIcon className="w-4 h-4" />
                Loot
            </button>
          ) : !isTrulyDead ? (
              <>
                 <button 
                    onClick={() => setIsManagingConditions(true)}
                    className="p-2 bg-stone-600 hover:bg-stone-500 text-white rounded-md transition"
                    aria-label={`Manage conditions for ${participant.name}`}
                >
                    <PlusIcon className="w-4 h-4" />
                </button>
                <button 
                    onClick={() => setIsManagingHealth(true)} 
                    className="p-2 bg-stone-600 hover:bg-stone-500 text-white rounded-md transition"
                    disabled={!hasHp}
                    aria-label={`Manage health for ${participant.name}`}
                >
                    <HeartIcon className="w-4 h-4"/>
                </button>
              </>
          ) : null}
          <button
            onClick={handleDeleteClick}
            onBlur={() => {
                if (isConfirmingDelete) {
                    if (confirmDeleteTimeoutRef.current) clearTimeout(confirmDeleteTimeoutRef.current);
                    setIsConfirmingDelete(false);
                }
            }}
            className={`p-2 rounded-md transition ${
                isConfirmingDelete 
                ? 'bg-red-700 text-white' 
                : 'bg-stone-600 hover:bg-red-700 text-white'
            }`}
            aria-label={isConfirmingDelete ? `Confirm removal of ${participant.name}` : `Remove ${participant.name}`}
            >
            {isConfirmingDelete ? <CheckIcon className="w-4 h-4" /> : <TrashIcon className="w-4 h-4" />}
          </button>
        </div>

        {/* Legendary & Traits Rows */}
        {(hasLegendaryResistances || hasLegendaryActions) && (
            <div className={`col-span-12 mt-3 pt-3 border-t border-stone-700/60 grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-3 ${isInGroup ? 'pl-2' : ''}`}>
                {hasLegendaryResistances && (
                    <LegendaryTracker
                        label="Legendary Resistances"
                        max={participant.legendaryResistances!}
                        used={participant.legendaryResistancesUsed!}
                        onUpdate={(newUsed) => onUpdateParticipant(participant.id, { legendaryResistancesUsed: newUsed })}
                        Icon={DiamondIcon}
                        colorClass="text-amber-400"
                        usedColorClass="text-stone-600"
                    />
                )}
                {hasLegendaryActions && (
                    <LegendaryTracker
                        label="Legendary Actions"
                        max={participant.legendaryActions!}
                        used={participant.legendaryActionsUsed!}
                        onUpdate={(newUsed) => onUpdateParticipant(participant.id, { legendaryActionsUsed: newUsed })}
                        Icon={StarIcon}
                        colorClass="text-sky-400"
                        usedColorClass="text-stone-600"
                    />
                )}
            </div>
        )}

        {(participant.type === 'creature' || participant.type === 'dmpc') && <TraitGrid participant={participant} />}
      </div>

      {/* Modals */}
      {isManagingConditions && (
        <ConditionManager
          participant={participant}
          onAdd={(condition) => onAddCondition(participant.id, condition)}
          onRemove={(conditionId) => onRemoveCondition(participant.id, conditionId)}
          onClose={() => setIsManagingConditions(false)}
        />
      )}
      {isManagingHealth && (
        <HealthManagerModal
            participant={participant}
            onUpdateParticipant={onUpdateParticipant}
            onClose={() => setIsManagingHealth(false)}
        />
      )}
    </>
  );
};

import React, { useState } from 'react';
import type { Participant } from '../types';
import { HeartMinusIcon, HeartPlusIcon, TempHpIcon, MaxHpIcon, CloseIcon } from './icons';

interface HealthManagerModalProps {
  participant: Participant;
  onUpdateParticipant: (id: string, updates: Partial<Participant>) => void;
  onClose: () => void;
}

const ActionInput: React.FC<{
    Icon: React.ElementType;
    label: string;
    value: string;
    onChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onConfirm: () => void;
    buttonText: string;
    iconColorClass: string;
    buttonColorClass: string;
    placeholder?: string;
}> = ({ Icon, label, value, onChange, onConfirm, buttonText, iconColorClass, buttonColorClass, placeholder }) => {
    const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            onConfirm();
        }
    };

    return (
        <div className="bg-stone-700/50 p-4 rounded-lg">
            <label className="flex items-center gap-2 text-lg font-bold text-stone-200 mb-2">
                <Icon className={`w-6 h-6 ${iconColorClass}`} />
                {label}
            </label>
            <div className="flex gap-2">
                <input
                    type="number"
                    value={value}
                    onChange={onChange}
                    onKeyDown={handleKeyDown}
                    className="w-full bg-stone-900/50 border border-stone-600 rounded-md px-3 py-2 text-white focus:ring-2 focus:ring-amber-500 transition"
                    placeholder={placeholder || 'Amount'}
                    autoFocus={label === "Damage"} // Autofocus damage input
                />
                <button
                    onClick={onConfirm}
                    className={`px-4 py-2 text-white font-semibold rounded-md transition duration-300 ease-in-out disabled:bg-stone-700 disabled:opacity-50 disabled:cursor-not-allowed flex-shrink-0 ${buttonColorClass}`}
                    disabled={!value}
                >
                    {buttonText}
                </button>
            </div>
        </div>
    );
}

export const HealthManagerModal: React.FC<HealthManagerModalProps> = ({ participant, onUpdateParticipant, onClose }) => {
  const [damage, setDamage] = useState('');
  const [heal, setHeal] = useState('');
  const [maxHp, setMaxHp] = useState((participant.maxHp || '').toString());
  const [tempHp, setTempHp] = useState('');

  const handleDamage = () => {
    const damageAmount = parseInt(damage, 10);
    if (isNaN(damageAmount) || damageAmount <= 0) return;

    const currentTempHp = participant.tempHp || 0;
    const currentHp = participant.hp || 0;
    const currentMaxHp = participant.maxHp || 0;

    const tempHpDamage = Math.min(currentTempHp, damageAmount);
    const newTempHp = currentTempHp - tempHpDamage;

    const remainingDamage = damageAmount - tempHpDamage;
    const newHp = Math.max(0, currentHp - remainingDamage);

    // Instant Death rule: If remaining damage (after temp hp) reduces you to 0 HP
    // and the leftover damage equals or exceeds your HP maximum.
    const excessDamage = remainingDamage - currentHp;
    const isInstantDead = excessDamage >= currentMaxHp && (participant.type === 'player' || participant.type === 'dmpc');

    onUpdateParticipant(participant.id, { 
        hp: newHp, 
        tempHp: newTempHp, 
        isInstantDead: isInstantDead || participant.isInstantDead 
    });
    onClose();
  };

  const handleHeal = () => {
    const healAmount = parseInt(heal, 10);
    if (isNaN(healAmount) || healAmount <= 0) return;

    const currentHp = participant.hp || 0;
    const currentMaxHp = participant.maxHp || 0;
    const newHp = Math.min(currentMaxHp, currentHp + healAmount);

    onUpdateParticipant(participant.id, { hp: newHp });
    onClose();
  };

  const handleSetTempHp = () => {
    const tempHpAmount = parseInt(tempHp, 10);
    if (isNaN(tempHpAmount) || tempHpAmount < 0) return;

    // Per D&D rules, new Temp HP replaces old unless the old is greater.
    const newTempHp = Math.max(participant.tempHp || 0, tempHpAmount);

    onUpdateParticipant(participant.id, { tempHp: newTempHp });
    onClose();
  };

  const handleSetMaxHp = () => {
    const maxHpAmount = parseInt(maxHp, 10);
    if (isNaN(maxHpAmount) || maxHpAmount < 1) return;

    // Ensure current HP isn't higher than new max HP
    const newHp = Math.min(participant.hp || 0, maxHpAmount);

    onUpdateParticipant(participant.id, { hp: newHp, maxHp: maxHpAmount });
    onClose();
  };

  return (
    <div
      className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4"
      onClick={onClose}
    >
      <div
        className="bg-stone-800 rounded-lg shadow-xl p-6 border border-stone-700 w-full max-w-md m-4"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-2xl font-medieval text-white">
            Health Manager: {participant.name}
          </h3>
          <button onClick={onClose} className="text-stone-400 hover:text-white">
            <CloseIcon className="w-6 h-6"/>
          </button>
        </div>

        <div className="text-center bg-stone-900/50 p-3 rounded-lg mb-4 border border-stone-700">
            <span className="text-2xl font-bold text-white">
                {participant.hp}
                {(participant.tempHp ?? 0) > 0 && <span className="text-sky-400"> +{participant.tempHp}</span>}
                / {participant.maxHp} HP
            </span>
        </div>

        <div className="space-y-4">
            <ActionInput 
                Icon={HeartMinusIcon}
                label="Damage"
                value={damage}
                onChange={(e) => setDamage(e.target.value)}
                onConfirm={handleDamage}
                buttonText="Apply"
                iconColorClass="text-red-400"
                buttonColorClass="bg-red-700 hover:bg-red-600"
            />
            <ActionInput 
                Icon={HeartPlusIcon}
                label="Heal"
                value={heal}
                onChange={(e) => setHeal(e.target.value)}
                onConfirm={handleHeal}
                buttonText="Apply"
                iconColorClass="text-emerald-400"
                buttonColorClass="bg-emerald-700 hover:bg-emerald-600"
            />
             <ActionInput 
                Icon={TempHpIcon}
                label="Set Temporary HP"
                value={tempHp}
                onChange={(e) => setTempHp(e.target.value)}
                onConfirm={handleSetTempHp}
                buttonText="Set"
                iconColorClass="text-sky-400"
                buttonColorClass="bg-sky-700 hover:bg-sky-600"
            />
             <ActionInput 
                Icon={MaxHpIcon}
                label="Set Max HP"
                value={maxHp}
                onChange={(e) => setMaxHp(e.target.value)}
                onConfirm={handleSetMaxHp}
                buttonText="Set"
                iconColorClass="text-amber-400"
                buttonColorClass="bg-amber-700 hover:bg-amber-600"
            />
        </div>
      </div>
    </div>
  );
};

